    y bigint
);


ALTER TABLE config.grid OWNER TO postgres;

--
-- Name: measurement; Type: TABLE; Schema: raw; Owner: scanner_rw
--

CREATE TABLE raw.measurement (
    measurement_id bigint NOT NULL,
    measurement_value double precision NOT NULL,
    scan_id bigint,
    x integer,
    y integer,
    modified_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP
);


ALTER TABLE raw.measurement OWNER TO scanner_rw;

--
-- Name: measurement_measurement_id_seq; Type: SEQUENCE; Schema: raw; Owner: scanner_rw
--

ALTER TABLE raw.measurement ALTER COLUMN measurement_id ADD GENERATED BY DEFAULT AS IDENTITY (
    SEQUENCE NAME raw.measurement_measurement_id_seq
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1
);


--
-- Name: measurement_stretched; Type: VIEW; Schema: raw; Owner: postgres
--

CREATE VIEW raw.measurement_stretched AS
 SELECT measurement_id,
    measurement_value,
    scan_id,
    x,
    y,
    modified_at AS modified_at_raw,
    (min(modified_at) OVER () + ((modified_at - min(modified_at) OVER ()) * (5000)::double precision)) AS modified_at
   FROM raw.measurement m;


ALTER VIEW raw.measurement_stretched OWNER TO postgres;

--
-- Name: scan_id_sequence; Type: SEQUENCE; Schema: raw; Owner: postgres
--

CREATE SEQUENCE raw.scan_id_sequence
    START WITH 1
    INCREMENT BY 1
    NO MINVALUE
    NO MAXVALUE
    CACHE 1;


ALTER SEQUENCE raw.scan_id_sequence OWNER TO postgres;

